DOMAIN_SUMMARY = 'Customer support often involves repetitive tasks like categorizing tickets and drafting replies based on common issues. This project automates these initial steps using a collaborative AI agent team, improving efficiency and response times for support agents. It focuses on handling common, well-documented queries, allowing human agents to focus on complex or unique customer problems.'
USER_PERSONA = 'Support Agent Sarah: Sarah is a customer support agent who frequently receives common customer inquiries. She wants a tool that can quickly categorize tickets and provide a first draft of a reply, referencing relevant information, so she can review, refine, and send it faster. She values accuracy, context, and efficiency.'
STARTER_QUESTIONS = ['How would you integrate this system with an existing CRM?', 'What are the challenges of making AI-generated replies sound human and empathetic?', 'How can you improve the knowledge base search accuracy for agents?', 'What security considerations are important when handling customer data?', 'How would you scale this system to handle thousands of tickets daily?']
WORKFLOW_STEPS = ["1: User creates a new support ticket via the frontend (or it's ingested by the backend).", "2: Backend API receives the new ticket and stores it in the database with status 'New'.", "3: Backend triggers the 'TicketCategorizer' agent with the new ticket's description.", "4: TicketCategorizer agent analyzes the description and assigns a predefined category (e.g., 'Billing', 'Technical Issue', 'Feature Request').", "5: The assigned category is saved back to the ticket in the database, and the ticket status updates to 'Categorized'.", "6: Backend triggers the 'ReplyGenerator' agent with the ticket description and the newly assigned category.", "7: ReplyGenerator agent uses the 'KnowledgeBaseSearch' tool to find relevant articles based on the ticket description and category.", '8: ReplyGenerator agent drafts a reply incorporating information from the retrieved knowledge base articles, maintaining a helpful and professional tone.']
BUSINESS_RULES = ['All new tickets must be categorized within 5 minutes of creation.', 'A reply draft must be generated for all categorized tickets.', 'Reply drafts should always include a polite closing and suggest next steps if applicable.', "Knowledge base articles are the primary source of factual information for replies; agents should not 'hallucinate' solutions.", "The system should flag tickets as 'Complex' if agents cannot find relevant KB articles or categorize with high confidence.", 'Maximum length for generated replies should be 300 words to keep them concise.']
